const SUPABASE_URL = 'https://faklxfakgzkpkbxfihzh.supabase.co';
const SUPABASE_SERVICE_KEY = 'REDACTED_SUPABASE_KEY';
const SUPABASE_API_KEY = 'REDACTED_SUPABASE_KEY';
const trigger = $('workflow_trigger').first().json;
const userId = trigger.user_id || '';

let recipient_email = trigger.recipient_email;
let bcc_email = trigger.bcc_email;
let story_structure_guidelines = '';
try {
  const rows = await this.helpers.httpRequest({
    method: 'GET',
    url: `${SUPABASE_URL}/rest/v1/app_config_v2?key=in.(recipient_email,bcc_email,story_structure_guidelines)&select=key,value&user_id=eq.${encodeURIComponent(userId)}`,
    headers: { 'apikey': SUPABASE_API_KEY, 'Authorization': `Bearer ${SUPABASE_API_KEY}` }
  });
  for (const row of rows) {
    if (row.key === 'recipient_email' && !recipient_email) recipient_email = row.value;
    if (row.key === 'bcc_email' && !bcc_email) bcc_email = row.value;
    if (row.key === 'story_structure_guidelines') story_structure_guidelines = row.value;
  }
} catch (e) {
  if (!recipient_email) recipient_email = 'eric@agileadtesting.com';
}


// Load story arcs for write_chapter
let book_arc_prompt = '';
let book_arc_name = '';
let chapter_arc_prompt = '';
let chapter_arc_name = '';
let project_genre_slug = trigger.genre_slug || '';
const projectTitle = trigger.project_title || '';
// Try to get book arc from project outline
if (projectTitle) {
  try {
    const projResp = await this.helpers.httpRequest({
      method: 'GET',
      url: SUPABASE_URL + '/rest/v1/writing_projects_v2?title=ilike.*' + encodeURIComponent(projectTitle) + '*&select=outline,genre_slug&limit=1&user_id=eq.' + encodeURIComponent(userId),
      headers: { 'apikey': SUPABASE_API_KEY, 'Authorization': 'Bearer ' + SUPABASE_API_KEY }
    });
    if (Array.isArray(projResp) && projResp.length > 0) {
      // DB is authoritative for genre_slug. Override any value the hub agent guessed.
      if (projResp[0].genre_slug) project_genre_slug = projResp[0].genre_slug;
      if (projResp[0].outline) {
      const bookArc = projResp[0].outline.story_arc_name || '';
      if (bookArc) {
        book_arc_name = bookArc;
        try {
          const arcs = await this.helpers.httpRequest({
            method: 'GET',
            url: SUPABASE_URL + '/rest/v1/story_arcs_v2?name=ilike.*' + encodeURIComponent(bookArc) + '*&limit=1',
            headers: { 'apikey': SUPABASE_API_KEY, 'Authorization': 'Bearer ' + SUPABASE_API_KEY }
          });
          if (Array.isArray(arcs) && arcs.length > 0) book_arc_prompt = arcs[0].prompt_text;
        } catch (e) {}
      }
      // Check for chapter-level story arc
      const rawCh = (trigger.chapter_number || '').toString().trim();
      const chNum = /^(prologue|prol|0)$/i.test(rawCh) ? 0 : (/^(epilogue|epil)$/i.test(rawCh) ? -1 : parseInt(rawCh));
      const chapters = projResp[0].outline.chapters || [];
      let thisCh = chapters.find(ch => ch.number === chNum);
      if (!thisCh && chNum === 0) thisCh = chapters.find(ch => /prologue/i.test(ch.title));
      if (thisCh?.chapter_outline?.chapter_story_arc) {
        chapter_arc_name = thisCh.chapter_outline.chapter_story_arc;
        if (chapter_arc_name !== book_arc_name) {
          try {
            const arcs = await this.helpers.httpRequest({
              method: 'GET',
              url: SUPABASE_URL + '/rest/v1/story_arcs_v2?name=ilike.*' + encodeURIComponent(chapter_arc_name) + '*&limit=1',
              headers: { 'apikey': SUPABASE_API_KEY, 'Authorization': 'Bearer ' + SUPABASE_API_KEY }
            });
            if (Array.isArray(arcs) && arcs.length > 0) chapter_arc_prompt = arcs[0].prompt_text;
          } catch (e) {}
        }
      }
    }
    }
  } catch (e) {}
}

// Check if project has embeddings, if not trigger embedding
let embeddings_ready = false;
if (projectTitle) {
  try {
    const embCheck = await this.helpers.httpRequest({
      method: 'GET',
      url: SUPABASE_URL + '/rest/v1/writing_embeddings_v2?project_id=eq.' + encodeURIComponent(projResp[0]?.id || '') + '&limit=1&select=id',
      headers: { 'apikey': SUPABASE_API_KEY, 'Authorization': 'Bearer ' + SUPABASE_API_KEY }
    });
    embeddings_ready = Array.isArray(embCheck) && embCheck.length > 0;
  } catch (e) {}
}

return [{ json: { embeddings_ready, book_arc_prompt, book_arc_name, chapter_arc_prompt, chapter_arc_name, SUPABASE_SERVICE_KEY, SUPABASE_URL, SUPABASE_API_KEY, recipient_email, bcc_email: bcc_email || '', story_structure_guidelines, userId, genre_slug: project_genre_slug } }];

// Validate inputs and fire async worker
const trigger = $('workflow_trigger').first().json;
const settings = $('settings').first().json;
const N8N_URL = 'https://n8n.agileadautomation.com';

const rawCh = (trigger.chapter_number || '').toString().trim();
const isProl = /^(prologue|prol|0)$/i.test(rawCh);
const isEpil = /^(epilogue|epil)$/i.test(rawCh);
const chapterLabel = isProl ? 'Prologue' : (isEpil ? 'Epilogue' : 'Chapter ' + rawCh);

// Validate: must have project_title and chapter_number
if (!trigger.project_title) {
  return [{ json: { result: 'Error: No project_title provided. Please specify which book to write.' } }];
}
if (!trigger.chapter_number && trigger.chapter_number !== 0) {
  return [{ json: { result: 'Error: No chapter_number provided. Please specify which chapter to write.' } }];
}

// Validate: check if project exists and has chapter outline
const supabaseUrl = settings.SUPABASE_URL;
const apiKey = settings.SUPABASE_API_KEY;
const userId = settings.userId;
const headers = { 'apikey': apiKey, 'Authorization': 'Bearer ' + apiKey };

let project = null;
try {
  const resp = await this.helpers.httpRequest({
    method: 'GET',
    url: supabaseUrl + '/rest/v1/writing_projects_v2?title=ilike.' + encodeURIComponent(trigger.project_title) + '&user_id=eq.' + encodeURIComponent(userId) + '&limit=1',
    headers
  });
  if (Array.isArray(resp) && resp.length > 0) project = resp[0];
} catch(e) {}

if (!project || !project.outline) {
  return [{ json: { result: 'Error: No outline found for "' + trigger.project_title + '". Please brainstorm the story first.' } }];
}

// Check chapter outline exists
const outline = project.outline;
const chNum = isProl ? 0 : (isEpil ? -1 : parseInt(rawCh));
let thisChapter = null;
if (outline.chapters) {
  if (isProl) {
    thisChapter = outline.chapters[0];
  } else if (isEpil) {
    thisChapter = outline.chapters[outline.chapters.length - 1];
  } else {
    thisChapter = outline.chapters.find(ch => ch.number === chNum);
  }
}

if (!thisChapter || !thisChapter.chapter_outline || !thisChapter.chapter_outline.sub_chapters || thisChapter.chapter_outline.sub_chapters.length === 0) {
  return [{ json: { result: 'Error: No chapter outline found for ' + chapterLabel + ' of "' + trigger.project_title + '". Please create a chapter outline first: "create a chapter outline for ' + chapterLabel.toLowerCase() + '"' } }];
}

const subCount = thisChapter.chapter_outline.sub_chapters.length;

// Fire the worker webhook (async - don't wait for completion)
const workerPayload = {
  genre_slug: settings.genre_slug || trigger.genre_slug || '',  // DB value (via settings) takes precedence over hub agent guess
  project_title: trigger.project_title,
  chapter_number: trigger.chapter_number,
  brief: trigger.brief || '',
  outline: trigger.outline || '',
  research_topics: trigger.research_topics || '',
  user_prompt: trigger.user_prompt || '',
  words_per_section: trigger.words_per_section || '',
  userId: userId,
  SUPABASE_URL: supabaseUrl,
  SUPABASE_API_KEY: apiKey,
  recipient_email: settings.recipient_email || '',
  bcc_email: settings.bcc_email || '',
  story_structure_guidelines: settings.story_structure_guidelines || '',
  book_arc_prompt: settings.book_arc_prompt || '',
  book_arc_name: settings.book_arc_name || '',
  chapter_arc_prompt: settings.chapter_arc_prompt || '',
  chapter_arc_name: settings.chapter_arc_name || '',
  genre_slug_settings: settings.genre_slug || ''
};

try {
  await this.helpers.httpRequest({
    method: 'POST',
    url: N8N_URL + '/webhook/write-chapter-worker-v2',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify(workerPayload),
    timeout: 5000
  });
} catch(e) {
  // Worker responds immediately but connection might still error - that's ok
  // as long as the request was sent
  if (!e.message?.includes('timeout') && !e.message?.includes('ECONNRESET')) {
    return [{ json: { result: 'Error: Could not start chapter writing. ' + (e.message || 'Unknown error') } }];
  }
}

return [{ json: { 
  result: chapterLabel + ' of "' + trigger.project_title + '" is now being written (' + subCount + ' sub-chapters). This will take approximately 10-15 minutes. You will receive an email with the completed chapter and a quality report when it is done. You do not need to wait here.'
} }];
